const body = $input.first().json.body || $input.first().json;
const spec = body.spec || '';
const pytestOutput = body.pytest_output || '';
const files = body.files || [];

if (!spec) throw new Error('Missing required field: spec');
if (!pytestOutput) throw new Error('Missing required field: pytest_output');
if (!files.length) throw new Error('Missing required field: files');

const filesBlock = files.map(f => `--- ${f.filename} ---\n${f.content}`).join('\n\n');

const systemPrompt = `You are a debugging engineer fixing a Python FastAPI project.
The SPEC below is the ONLY source of truth. When spec and test conflict, the spec wins.

Decision rules (apply in order):
1. Test asserts a value that CONTRADICTS the spec -> fix the TEST (wrong expected value)
2. Code computes a value that CONTRADICTS the spec -> fix the CODE
3. Tests fail due to shared global state between tests -> fix test_main.py:
   - add 'import routes' at the top (after other imports)
   - add @pytest.fixture(autouse=True) that calls .clear() on every in-memory store dict and resets global counters to 1
4. Endpoint or field is missing but required by spec -> add it to the relevant file

Version rules (never violate):
- Pydantic v2: from pydantic import BaseModel, Field  (never pydantic.v1 or pydantic.v2)
- httpx tests: from httpx import AsyncClient, ASGITransport
  async with AsyncClient(transport=ASGITransport(app=app), base_url='http://test') as client:
- Monetary values: store as INTEGER cents, return as format(cents / 100, '.2f')

Output EXACTLY ONE file — the one you fixed. Write it complete (every line, not a diff).
Start your response with exactly: # FILE: <filename>
Then the full corrected file. No markdown fences, no explanations, never output more than one file.`;

const userContent = `SPEC (source of truth):
${spec}

PYTEST FAILURE OUTPUT:
${pytestOutput}

CURRENT PROJECT FILES:
${filesBlock}`;

const ollamaBody = JSON.stringify({
  model: 'qwen2.5-coder:32b',
  stream: false,
  options: { temperature: 0.1 },
  messages: [
    { role: 'system', content: systemPrompt },
    { role: 'user', content: userContent }
  ]
});

return [{ json: { ollamaBody } }];

const raw = $input.first().json.message?.content || '';

// Strip markdown fences if model wrapped the output
const cleaned = raw
  .replace(/^```[\w]*\n?/m, '')
  .replace(/\n?```$/m, '')
  .trim();

// Extract filename from # FILE: comment if present
const filenameMatch = cleaned.match(/^# FILE: (.+)/m);
const filename = filenameMatch ? filenameMatch[1].trim() : 'unknown.py';

const lines = cleaned.split('\n').length;

return [{ json: { filename, content: cleaned, lines } }];
